proof_block:
// The ensures of `det_push` is an implication
//     (big AND of post1_/post2_ facts) ==> det_push_equal(r1, r2, post1_, post2_)
// so the post1_/post2_ facts are NOT free hypotheses in the body — they only
// live on the LHS of that implication.  The previous attempt asserted them
// flat and Verus rejected the very first `assert(post1_self_@ == ...)` for
// exactly that reason.
//
// The fix: wrap the proof of the consequent in `if antecedent { ... }`.
// Inside the branch the antecedent IS in scope, so each post1_/post2_
// ensures is a usable hypothesis, and on exit we have established
// `antecedent ==> consequent` — which is exactly the ensures.
if (post1_self_.wf())
    && (post1_self_@ == pre_self_@.push(*new_value))
    && (post1_self_.len() == pre_self_.len() + 1)
    && (forall|v: T| #![auto]
        pre_self_@.contains(v) ==>
            pre_self_.get_node_ref(v) == post1_self_.get_node_ref(v))
    && (post1_self_.get_node_ref(*new_value) == r1)
    && (post1_self_.unique())
    && (post2_self_.wf())
    && (post2_self_@ == pre_self_@.push(*new_value))
    && (post2_self_.len() == pre_self_.len() + 1)
    && (forall|v: T| #![auto]
        pre_self_@.contains(v) ==>
            pre_self_.get_node_ref(v) == post2_self_.get_node_ref(v))
    && (post2_self_.get_node_ref(*new_value) == r2)
    && (post2_self_.unique())
{
    // View / spec_seq equality, via Seq extensionality on the shared rhs
    // `pre_self_@.push(*new_value)`.
    assert(post1_self_@ == pre_self_@.push(*new_value));
    assert(post2_self_@ == pre_self_@.push(*new_value));
    assert(post1_self_@ =~= post2_self_@);
    assert(post1_self_@ == post2_self_@);
    assert(post1_self_.view() == post2_self_.view());

    // Pin r1 / r2 to their respective get_node_ref values.
    assert(post1_self_.get_node_ref(*new_value) == r1);
    assert(post2_self_.get_node_ref(*new_value) == r2);

    // Force both #[auto]-triggered `forall|v: T|` ensures to be instantiated
    // on the same v so that, for any v already in pre_self_, the get_node_ref
    // values from the two runs are forced equal through pre_self_.get_node_ref(v).
    assert forall|v: T| pre_self_@.contains(v) implies
        post1_self_.get_node_ref(v) == post2_self_.get_node_ref(v) by {
        assert(pre_self_.get_node_ref(v) == post1_self_.get_node_ref(v));
        assert(pre_self_.get_node_ref(v) == post2_self_.get_node_ref(v));
    }
}
